def get_unique(tup):
    # किसी भी प्रकार के डेटा को संभालने के लिए डिक्शनरी का उपयोग करेंगे
    unique_count = {}

    # ट्यूपल के प्रत्येक मान के लिए एक अद्वितीय सूची बनाएंगे
    for value in tup:
        # यदि मान पहले से ही अद्वितीय सूची में है, तो उसे बढ़ाएंगे
        if value in unique_count:
            unique_count[value].append(value)
        # यदि मान पहले से ही अद्वितीय सूची में नहीं है, तो एक नया सूची बनाएंगे और उसे अद्वितीय सूची में जोड़ेंगे
        else:
            unique_count[value] = [value]

    # अद्वितीय सूची की गिनती करेंगे
    unique_count = {key: len(value) for key, value in unique_count.items()}

    return unique_count

# उदाहरण के लिए, ट्यूपल के लिए अद्वितीय मानों की गिनती करें
tup = (1, 2, 2, 3, 3, 3, 4, 4, 4, 4)
print(get_unique(tup))  # {1: 1, 2: 2, 3: 3, 4: 4}
```

