def get_max_occuring_char(s):
    # स्ट्रिंग को एक डिक्शनरी में परिवर्तित करें जहां कुंजी है अक्षर और मान है उसकी आवृत्ति
    char_frequency = {}
    for char in s:
        if char in char_frequency:
            char_frequency[char] += 1
        else:
            char_frequency[char] = 1

    # डिक्शनरी में सबसे अधिक मान वाले अक्षर को ढूंढें
    max_frequency = max(char_frequency.values())
    max_chars = [char for char, frequency in char_frequency.items() if frequency == max_frequency]

    # यदि स्ट्रिंग में एक अक्षर की अधिकतम आवृत्ति है, तो उस अक्षर को वापस करें, अन्यथा सभी अक्षरों को वापस करें जिनकी आवृत्ति सबसे अधिक है
    if len(max_chars) == 1:
        return max_chars[0]
    else:
        return max_chars

# परीक्षण
print(get_max_occuring_char("aabbbcc"))  # b
print(get_max_occuring_char("abcdef"))  # None
print(get_max_occuring_char("aaa"))  # a
print(get_max_occuring_char("aabbcc"))  # a और b
```

