```python
def divisible_by_digits(start, end):
    # सभी संख्याओं की जांच करने के लिए एक फ़ंक्शन बनाएं
    def is_divisible(n):
        # संख्या के प्रत्येक अंक की जांच करें कि वह संख्या को कितनी बार विभाजित करता है
        for digit in str(n):
            # यदि संख्या का कोई अंक है जो संख्या को विभाजित नहीं करता है, तो संख्या विभाज्य नहीं है
            if n % int(digit) != 0:
                return False
        # यदि संख्या का कोई अंक नहीं है जो संख्या को विभाजित नहीं करता है, तो संख्या विभाज्य है
        return True

    # दिए गए शुरुआती और अंतिम सीमा के बीच सभी संख्याओं की जांच करें
    for num in range(start, end + 1):
        # यदि संख्या विभाज्य है, तो इसे वापस करें
        if is_divisible(num):
            yield num

# उदाहरण के लिए, 10 से 100 तक की संख्याओं की जांच करें
for num in divisible_by_digits(10, 100):
    print(num)
```

इस कोड में, हम एक फ़ंक्शन `divisible_by_digits` बनाते हैं जो दिए गए शुरुआती और अंतिम सीमा के बीच सभी संख्याओं की जांच करता है जो प्रत्येक अंक से विभाज्य हैं। इसे करने के लिए, हम एक अन्य फ़ंक्शन `is_divisible` बनाते हैं जो एक संख्या के प्रत्येक अंक की जांच करता है कि वह संख्या को कितनी बार विभाजित करता है। यदि कोई अंक नहीं है जो संख्या को विभाजित नहीं करता है, तो संख्या विभाज्य है।

```python
def sum_digits_single(n):
    # यदि संख्या एक अंक है, तो हमें उसे ही वापस करना होगा
    if n < 10:
        return n

    # संख्या के अंतिम अंक को अलग करें
    last_digit = n % 10

    # संख्या को अंतिम अंक के बिना छोड़ दें
    remaining_number = n // 10

    # यदि अंतिम अंक से शेष संख्या के अंकों के योग से अधिक है, तो अंतिम अंक को अलग करें और शेष संख्या को वापस करें
    if last_digit > sum_digits(remaining_number):
        return last_digit + sum_digits(remaining_number)

    # यदि अंतिम अंक से शेष संख्या के अंकों के योग कम है, तो शेष संख्या को वापस करें और अंतिम अंक को अलग करें
    else:
        return sum_digits(remaining_number) + last_digit

def sum_digits(n):
    # संख्या के अंकों का योग ज्ञात करें
    return sum(int(digit) for digit in str(n))
```

