def find_gcd(arr):
    # यदि सूची में एक या दो तत्व हैं, तो उनका गुणनखंड ही उनका गुणनखंड होगा
    if len(arr) <= 2:
        return gcd(arr[0], arr[1]) if len(arr) == 2 else arr[0]

    # सूची के पहले और आखिरी तत्वों का गुणनखंड निकालें
    first_gcd = gcd(arr[0], arr[-1])

    # सूची के बाकी तत्वों के लिए एक नया सूची बनाएं
    rest_arr = [num for num in arr[1:-1] if num != first_gcd]

    # यदि बाकी की सूची में तत्व हैं, तो उनका गुणनखंड निकालें और पहले तत्व के साथ गुणनखंड निकालें
    if rest_arr:
        return find_gcd([first_gcd] + rest_arr)
    else:
        # यदि बाकी की सूची में कोई तत्व नहीं है, तो पहले तत्व का गुणनखंड ही गुणनखंड होगा
        return first_gcd

def gcd(a, b):
    # यदि दूसरा संख्या शून्य है, तो पहली संख्या ही गुणनखंड होगा
    if b == 0:
        return a
    else:
        # अन्यथा, दोनों संख्याओं का गुणनखंड उनके गुणनखंड के बराबर होगा
        return gcd(b, a % b)
```

